select count(1)
from search_operations

  and deleted = false

    and keyword like concat('%', #{keyword}, '%')


    and scene = #{scene}


    and status = #{status}

select keyword_id, keyword, scene, sort_no, status, effect_time_range, synonym_text, created_at, updated_at, created_by, updated_by, deleted
from search_operations

  and deleted = false

    and keyword like concat('%', #{keyword}, '%')


    and scene = #{scene}


    and status = #{status}


order by sort_no asc, keyword_id asc
limit #{pageSize} offset #{offset}

